SELECT * FROM (
SELECT ROWNUM AS rn, A.* FROM(
SELECT AT.*, C.note AS category_name
FROM attach_file AT
LEFT JOIN common_code C ON AT.file_code = C.code_id



		AT.project_id = #{projectId}



		AND AT.file_code = #{fileCode}



		AND AT.original_name LIKE '%' || #{originalName} || '%'


		AND AT.upload_user_id LIKE '%' || #{uploadUserId} || '%'


		AND TO_CHAR(AT.upload_date, 'YYYY-MM-DD') >= #{startDate}


		AND TO_CHAR(AT.upload_date, 'YYYY-MM-DD')  <=  #{endDate}


ORDER BY AT.upload_date DESC
) A
)
WHERE rn BETWEEN #{startRow} AND #{endRow}

