project_id = #{projectId}, version_id = #{versionId}, file_code = #{fileCode}, original_name = #{originalName}, stored_name = #{storedName}, file_path = #{filePath}, file_size = #{fileSize}, file_version = #{fileVersion}, file_use_yn = #{fileUseYn}, connect_address = #{connectAddress},
